#start textdef showStart():#print a title and the commands    print('''Welcome to MinesweeperTo reveal tiles, type the coordinates like so: A3To flag or unflag mines, include an F afterwards: C4F''')rows = 5cols = 5solvedBoard = [[0 for _ in range(rows)] for _ in range(cols)] #full board of minesweeper numbers, mines are 11visibleBoard = [[9 for _ in range(rows)] for _ in range(cols)] #what the player sees, except 9 -> ' ' un-revealed safe tiles, 10 -> ' ' is un-revealed mines, 11 -> '💣' is revealed mines# 12 -> '🚩' flagged safe tiles, 13 -> '🚩' flagged minesfirstMove = Truegame = True #this becomes false when the game ends to check for an input before beginning a new gamedef showBoard():    #print the board    print("---------------------------")    print("   A  B  C  D  E")    for i in range(rows):        row = f"{i + 1} "        for j in range(cols):            value = visibleBoard[i][j]            if value == 9 or value == 10:                row += f"[ ]"            elif value == 11:                row += f"💣 "            elif value == 12 or value == 13:                row += f"🚩 "            else:                cell = str(value)                row += f"[{cell}]"        print(row)    print("---------------------------")def newBoard(row, col):    import random    # all possible mine positions, every tile except row, col    positions = [(i, j) for i in range(rows) for j in range(cols) if (i, j) != (row, col)]    # pick 4 at random    chosen = random.sample(positions, 4)    # label them as mines in both tables    for i, j in chosen:        solvedBoard[i][j] = 11        visibleBoard[i][j] = 10    # put the minesweeper numbers in the solved board    for i in range(rows):        for j in range(cols):            if solvedBoard[i][j] == 11:                continue  # skip mines            # count surrounding mines            count = 0            for di in [-1, 0, 1]:                for dj in [-1, 0, 1]:                    if di == 0 and dj == 0:                        continue  # skip self                    ni, nj = i + di, j + dj                    if 0 <= ni < rows and 0 <= nj < cols:                        if solvedBoard[ni][nj] == 11:                            count += 1            solvedBoard[i][j] = count            def reveal(row, col):    if row == 100:        #this is called when the player loses: reveal all the mines, leave the rest of the board the same        for i in range(len(visibleBoard)):            for j in range(len(visibleBoard[i])):                if visibleBoard[i][j] == 10:                    visibleBoard[i][j] = 11    else:        #reveal a tile        visibleBoard[row][col] = solvedBoard[row][col]        if visibleBoard[row][col] == 0:            # check and reveal adjacent tiles (auto-fill)            for dr in [-1, 0, 1]:                for dc in [-1, 0, 1]:                    if dr == 0 and dc == 0:                        continue  # skip the original cell itself                    nr, nc = row + dr, col + dc                    # Check boundaries                    if 0 <= nr < rows and 0 <= nc < cols:                        if visibleBoard[nr][nc] == 9:                            reveal(nr, nc)                            def flag(row, col):    if visibleBoard[row][col] == 9:        visibleBoard[row][col] = 12    elif visibleBoard[row][col] == 10:        visibleBoard[row][col] = 13showStart()#loopwhile True:    if game:        showBoard()        #get input    s = ''    while s == '':        s = input('>')    if not game:        game = True        continue    #revealing tiles will always be 2 characters    if len(s) == 2:        if s[1].isdigit(): #make sure the second character is a number            row = int(s[1]) - 1            col = ord(s[0].lower()) - ord('a')            if row >= rows or col >= cols or s[1] == "0":                print("Those coordinates are out of range, try again.")             elif s[0].lower() in {"a", "b", "c", "d", "e"}:                if firstMove:                        # generate a board                        row = int(s[1]) - 1                        col = ord(s[0].lower()) - ord('a')                        newBoard(row, col)                        reveal(row, col)                        firstMove = False                else:                    # update the board                    row = int(s[1]) - 1                    col = ord(s[0].lower()) - ord('a')                    reveal(row, col)    #flagging is always 3    elif len(s) == 3 and s[2].lower() == "f":        #you can't start with a flag        if firstMove:           print("Try revealing a tile first. Your first guess is always safe!")         elif s[0].lower() in {"a", "b", "c", "d", "e"}:            if s[1] in {"1", "2", "3", "4", "5"}:                row = int(s[1]) - 1                col = ord(s[0].lower()) - ord('a')                flag(row, col)    else:        print("Invalid input, try again.")     #win logic    win = True    loss = False    for row in visibleBoard:        if 11 in row: #11's are revealed mines, you exploded!            win = False            loss = True            break    for row in visibleBoard:        if 9 in row or 12 in row: #9's and 12's are unrevealed safe tiles, if there are none then we won            win = False            break    if win:        print('YOU WIN!')        print('Input anything to play again')        #reset everything        solvedBoard = [[0 for _ in range(rows)] for _ in range(cols)]        visibleBoard = [[9 for _ in range(rows)] for _ in range(cols)]        firstMove = True        game = False    #loss logic    elif loss:        reveal(100, 0)        showBoard()        print('GAME OVER!')        print('Input anything to play again')        #reset everything        solvedBoard = [[0 for _ in range(rows)] for _ in range(cols)]        visibleBoard = [[9 for _ in range(rows)] for _ in range(cols)]        firstMove = True        game = False